const item = $input.first().json;
const headers = item.headers || {};
const body = item.body || {};

const expectedSecret = $env.WEBHOOK_SECRET;
const providedSecret = headers['x-webhook-secret'];

if (!expectedSecret || providedSecret !== expectedSecret) {
  throw new Error('Unauthorized: x-webhook-secret header missing or invalid');
}

return [{
  json: {
    name: String(body.name || '').trim(),
    email: String(body.email || '').trim().toLowerCase(),
    company: String(body.company || '').trim(),
    message: String(body.message || '').trim(),
    budget: String(body.budget || '').trim(),
  }
}];

const searchResult = $input.first().json;
const lead = $('Validate & Normalize').item.json;

const record = searchResult.records[0];
const existingMessage = record.fields.Message || '';
const timestamp = new Date().toISOString();
const appendedNote = '\n\n[Follow-up inquiry ' + timestamp + ']: ' + lead.message;

return [{
  json: {
    recordId: record.id,
    updatedMessage: existingMessage + appendedNote,
  }
}];

const response = $input.first().json;
const lead = $('Build Groq Prompt').item.json;

let content = '';
try {
  content = response.choices[0].message.content;
} catch (e) {
  content = '';
}

content = String(content || '').trim();
if (content.startsWith('```')) {
  content = content.replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/i, '').trim();
}

let parsed = null;
try {
  parsed = JSON.parse(content);
} catch (e) {
  parsed = null;
}

const allowedCategories = ['sales', 'support', 'partnership', 'spam'];

let category = 'unclassified';
let confidence = 0;
let reply_subject = '';
let reply_body = '';

if (parsed && typeof parsed === 'object') {
  const rawCategory = String(parsed.category || '').toLowerCase().trim();
  category = allowedCategories.includes(rawCategory) ? rawCategory : 'unclassified';
  const rawConfidence = typeof parsed.confidence === 'number' ? parsed.confidence : Number(parsed.confidence);
  confidence = Number.isFinite(rawConfidence) ? rawConfidence : 0;
  reply_subject = String(parsed.reply_subject || '').trim();
  reply_body = String(parsed.reply_body || '').trim();
}

const categoryLabel = category.charAt(0).toUpperCase() + category.slice(1);

return [{
  json: {
    name: lead.name,
    email: lead.email,
    company: lead.company,
    message: lead.message,
    budget: lead.budget,
    category,
    categoryLabel,
    confidence,
    reply_subject,
    reply_body,
  }
}];
